header('Content-Type: text/html; charset=utf-8');
echo '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Deploy Berulang</title><style>body{font-family:monospace;background:#1a1a2e;color:#e5e7eb;padding:30px}h2{color:#f59e0b}.ok{color:#34d399}.fail{color:#f87171}.info{color:#60a5fa}.skip{color:#94a3b8}pre{background:#0f172a;padding:20px;border-radius:8px}</style></head><body><h2>&#128295; iBook 2.0 &mdash; Deploy Tempahan Berulang</h2><pre>';
$base=__DIR__; $ok=0; $fail=0;
$files=[
'app/Http/Controllers/TempahanBerulangController.php'=>'',
'app/Models/TempahanBerulang.php'=>'',
'app/Models/Tempahan.php'=>'',
'app/Http/Requests/StoreTempahanBerulangRequest.php'=>'',
'app/Mail/PengesahanTempahanBerulang.php'=>'',
'app/Services/AuditLogger.php'=>'',
'app/Providers/AppServiceProvider.php'=>'',
'routes/web.php'=>'',
'config/ibook.php'=>'',
'resources/views/tempahan/create.blade.php'=>'',
'resources/views/tempahan/edit.blade.php'=>'',
'resources/views/emails/pengesahan-tempahan-berulang.blade.php'=>'',
];
echo "<span class='info'>[INFO]</span> Menulis ".count($files)." fail...\n\n";
foreach($files as $rp=>$b64){
    $fp=$base."/".$rp; $d=dirname($fp);
    if(!is_dir($d)) mkdir($d,0755,true);
    $c=base64_decode($b64);
    if(file_put_contents($fp,$c)!==false){echo "<span class='ok'>[OK]</span> ".htmlspecialchars($rp)." (".strlen($c)." bytes)\n"; $ok++;}
    else{echo "<span class='fail'>[GAGAL]</span> ".htmlspecialchars($rp)."\n"; $fail++;}
}
echo "\n-- DB SETUP --\n";
$ef=null;
foreach([__DIR__.'/.env',__DIR__.'/../.env'] as $l){if(file_exists($l)){$ef=realpath($l);break;}}
if(!$ef){echo "<span class='fail'>[GAGAL]</span> .env tidak dijumpai.\n";}
else{
    $dh=$dn=$du=$dp='';
    foreach(file($ef) as $b){$b=trim($b);
        if(str_starts_with($b,'DB_HOST='))     $dh=trim(substr($b,8)," \t\"'");
        if(str_starts_with($b,'DB_DATABASE=')) $dn=trim(substr($b,12)," \t\"'");
        if(str_starts_with($b,'DB_USERNAME=')) $du=trim(substr($b,12)," \t\"'");
        if(str_starts_with($b,'DB_PASSWORD=')) $dp=trim(substr($b,12)," \t\"'");
    }
    echo "<span class='info'>[INFO]</span> DB: {$du}@{$dh}/{$dn}\n";
    try{
        $pdo=new PDO("mysql:host={$dh};dbname={$dn};charset=utf8mb4",$du,$dp,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]);
        $pdo->exec("CREATE TABLE IF NOT EXISTS `tempahan_berulang` (
            `id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
            `ulid` VARCHAR(26) NOT NULL,
            `jenis` ENUM('mingguan','bulanan') NOT NULL,
            `setiap_n` TINYINT UNSIGNED NOT NULL DEFAULT 1,
            `hari_dalam_minggu` JSON NULL,
            `tarikh_mula` DATE NOT NULL,`tarikh_tamat` DATE NOT NULL,
            `sesi` JSON NOT NULL,`bilik_id` BIGINT UNSIGNED NOT NULL,
            `user_id` BIGINT UNSIGNED NOT NULL,`nama_mesyuarat` VARCHAR(255) NOT NULL,
            `bilangan_peserta` INT NOT NULL DEFAULT 1,`kategori` VARCHAR(255) NOT NULL,
            `nama_pengerusi` VARCHAR(255) NOT NULL,`tujuan` TEXT NULL,
            `created_at` TIMESTAMP NULL DEFAULT NULL,`updated_at` TIMESTAMP NULL DEFAULT NULL,
            PRIMARY KEY (`id`),UNIQUE KEY `tempahan_berulang_ulid_unique` (`ulid`),
            KEY `idx_tb_bilik` (`bilik_id`),KEY `idx_tb_user` (`user_id`),
            CONSTRAINT `fk_tb_bilik` FOREIGN KEY (`bilik_id`) REFERENCES `bilik_mesyuarat`(`id`) ON DELETE CASCADE,
            CONSTRAINT `fk_tb_user` FOREIGN KEY (`user_id`) REFERENCES `users`(`id`) ON DELETE CASCADE
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
        echo "<span class='ok'>[OK]</span> Jadual tempahan_berulang sedia.\n"; $ok++;
        $cols=$pdo->query("SHOW COLUMNS FROM `tempahan` LIKE 'tempahan_berulang_id'")->fetchAll();
        if(empty($cols)){
            $pdo->exec("ALTER TABLE `tempahan` ADD COLUMN `tempahan_berulang_id` BIGINT UNSIGNED NULL DEFAULT NULL AFTER `ulid`,ADD KEY `idx_tempahan_berulang_id` (`tempahan_berulang_id`),ADD CONSTRAINT `fk_tempahan_berulang` FOREIGN KEY (`tempahan_berulang_id`) REFERENCES `tempahan_berulang`(`id`) ON DELETE SET NULL");
            echo "<span class='ok'>[OK]</span> Lajur tempahan_berulang_id ditambah.\n"; $ok++;
        }else{echo "<span class='skip'>[SKIP]</span> Lajur tempahan_berulang_id sudah wujud.\n"; $ok++;}
    }catch(Exception $e){echo "<span class='fail'>[GAGAL DB]</span> ".htmlspecialchars($e->getMessage())."\n"; $fail++;}
}
$cc=__DIR__.'/bootstrap/cache/config.php';
if(file_exists($cc)&&@unlink($cc))echo "<span class='ok'>[OK]</span> Config cache dipadam.\n";
$vd=__DIR__.'/storage/framework/views'; $cl=0;
if(is_dir($vd))foreach(glob($vd.'/*.php')as $f)if(@unlink($f))$cl++;
echo "<span class='ok'>[OK]</span> $cl fail blade cache dipadam.\n\n";
