echo "──────────────────────────────\n<span style='color:$w'><b>Selesai: $ok berjaya, $fail gagal.</b></span>\n</pre>";
echo '<form method="post" action="?key='.PATCH_KEY.'&delete=1" style="margin-top:16px"><button style="background:#991b1b;color:#fff;border:none;padding:8px 18px;border-radius:6px;cursor:pointer">&#128465; Padam fail installer ini</button></form>';
if($_SERVER['REQUEST_METHOD']==='POST'&&($_GET['delete']??'')==='1'){@unlink(__FILE__);echo '<p style="color:#34d399;font-family:monospace">&#10003; Dipadamkan.</p>';}
